// src/landing/main.ts
var LEGACY_BOT_HANDLE = "parktaejun";
var DEFAULT_BOT_HANDLE = "your-bot";
var headline = document.querySelector("#headline");
var subheadline = document.querySelector("#subheadline");
var priceValue = document.querySelector("#price-value");
var includedUpdates = document.querySelector("#included-updates");
var brandName = document.querySelector("#brand-name");
var topbarPrimaryCta = document.querySelector("#topbar-primary-cta");
var heroDesktopCta = document.querySelector("#hero-desktop-cta");
var heroMobileCta = document.querySelector("#hero-mobile-cta");
var priceCardCta = document.querySelector("#price-card-cta");
var productACta = document.querySelector("#product-a-cta");
var productBCta = document.querySelector("#product-b-cta");
var compareProductALabel = document.querySelector("#compare-product-a-label");
var compareProductBLabel = document.querySelector("#compare-product-b-label");
var siteHost = document.body.dataset.siteHost?.trim() ?? "";
var initialLocaleHint = parseSupportedLocale(document.body.dataset.initialLocale);
var landingVariant = getLandingVariant(siteHost);
var storefront = null;
var msg = landingMessages.ko[landingVariant];
var currentLocale = getLocale(initialLocaleHint ?? "en");
var currentBotHandle = DEFAULT_BOT_HANDLE;
function buildTranslationDict(copy) {
  return Object.fromEntries(
    Object.entries(copy).filter(([, value]) => typeof value === "string")
  );
}
function normalizeBotHandle(value) {
  return `${value ?? ""}`.trim().replace(/^@+/, "") || DEFAULT_BOT_HANDLE;
}
function replaceLegacyBotHandle(value) {
  return value.replaceAll(`@${LEGACY_BOT_HANDLE}`, `@${currentBotHandle}`);
}
function applyBotHandleToCopy(value) {
  if (typeof value === "string") {
    return replaceLegacyBotHandle(value);
  }
  if (Array.isArray(value)) {
    return value.map((entry) => applyBotHandleToCopy(entry));
  }
  if (value && typeof value === "object") {
    return Object.fromEntries(
      Object.entries(value).map(([key, entry]) => [key, applyBotHandleToCopy(entry)])
    );
  }
  return value;
}
function setHref(element, href) {
  if (!element) {
    return;
  }
  element.setAttribute("href", href);
}
function renderLocalizedStorefront(locale) {
  const copy = applyBotHandleToCopy(landingStorefrontCopy[locale][landingVariant]);
  if (brandName) {
    brandName.textContent = copy.productName;
  }
  if (headline) {
    headline.innerHTML = copy.headline;
  }
  if (subheadline) {
    subheadline.textContent = copy.subheadline;
  }
  if (priceValue && storefront) {
    priceValue.textContent = storefront.settings.priceValue;
  }
  if (includedUpdates) {
    includedUpdates.textContent = copy.includedUpdates;
  }
  setHref(topbarPrimaryCta, copy.links.topbarPrimaryHref);
  setHref(priceCardCta, copy.links.priceCardHref);
  setHref(productACta, copy.links.productAHref);
  setHref(productBCta, copy.links.productBHref);
  if (heroDesktopCta) {
    heroDesktopCta.textContent = msg.productATitle;
  }
  if (heroMobileCta) {
    heroMobileCta.textContent = msg.productBTitle;
  }
  if (compareProductALabel) {
    compareProductALabel.textContent = msg.productATitle;
  }
  if (compareProductBLabel) {
    compareProductBLabel.textContent = msg.productBTitle;
  }
  document.title = [copy.productName, siteHost].filter(Boolean).join(" | ");
}
async function loadStorefront() {
  const response = await fetch("/api/public/storefront");
  if (!response.ok) {
    throw new Error("Could not load storefront data.");
  }
  storefront = await response.json();
  renderLocalizedStorefront(currentLocale);
}
async function loadBotConfig() {
  const response = await fetch("/api/public/bot/config");
  if (!response.ok) {
    throw new Error("Could not load bot config.");
  }
  const config = await response.json();
  currentBotHandle = normalizeBotHandle(config.botHandle);
  applyLocale(currentLocale);
}
function applyLocale(locale) {
  currentLocale = locale;
  msg = applyBotHandleToCopy(landingMessages[locale][landingVariant]);
  document.documentElement.lang = locale;
  applyTranslations(buildTranslationDict(msg));
  applyLangToggle(locale);
  renderLocalizedStorefront(locale);
}
void (async () => {
  msg = landingMessages[currentLocale][landingVariant];
  applyLocale(currentLocale);
  bindLangToggle((next) => {
    applyLocale(next);
  });
  await Promise.allSettled([
    loadBotConfig(),
    loadStorefront()
  ]);
})();
